// UB budget calculation:
//   inQueueX: 2 * tile * sizeof(float)
//   outQueueY: 2 * tile * sizeof(float)
//   tmpBuf1: 1 * tile * sizeof(float)
//   tmpBuf2: 1 * tile * sizeof(float)
//   scalarBuf: small
// Total bytes ~= 6 * tile * sizeof(float) = 24 * tile
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    SoftmaxCustomTilingData tiling;
    const uint32_t totalLength =
        static_cast<uint32_t>(context->GetInputShape(0)->GetOriginShape().GetShapeSize());

    // Infer 2D shape: (batchSize, innerDim)
    auto shape = context->GetInputShape(0)->GetOriginShape();
    const uint32_t batchSize = static_cast<uint32_t>(shape.GetDim(0));
    const uint32_t innerDim = static_cast<uint32_t>(shape.GetDim(1));

    // Compute tile length from UB budget
    uint32_t maxTile = UB_BUDGET_BYTES / 24;  // elements
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t tileLen = maxTile;
    if (innerDim < tileLen) {
        const uint32_t aligned = AlignDown(innerDim, ALIGN_ELEMS);
        tileLen = (aligned > 0) ? aligned : innerDim;
    }

    // blockDim: one block per row, but cap for stability
    uint32_t blockDim = batchSize;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

