class KernelSoftmaxCustom {
public:
    __aicore__ inline KernelSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t batchSize, uint32_t innerDim)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        batchSize_ = batchSize;
        innerDim_ = innerDim;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpBuf1_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpBuf2_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(scalarBuf_, 1, sizeof(float) * 4);
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0 || batchSize_ == 0 || innerDim_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Grid-stride over rows: each block processes rows blockIdx, blockIdx+blockNum, ...
        for (uint32_t row = blockIdx; row < batchSize_; row += blockNum) {
            ProcessRow(row);
        }
    }

private:
    // -----------------------------------------------------------------------
    // Softmax: 3-pass row processing
    //   Pass 1: find row max     (ReduceMax over all tiles)
    //   Pass 2: compute exp sum  (exp(x - max) -> ReduceSum)
    //   Pass 3: normalize        (exp(x - max) / sum)
    // -----------------------------------------------------------------------
    __aicore__ inline void ProcessRow(uint32_t row)
    {
        const uint32_t rowBase = row * innerDim_;
        const uint32_t numTiles = (innerDim_ + tileLen_ - 1) / tileLen_;

        // ---- Pass 1: find row maximum ----
        float rowMax = -1e38f;
        for (uint32_t t = 0; t < numTiles; t++) {
            const uint32_t offset = rowBase + t * tileLen_;
            const uint32_t len = (t == numTiles - 1) ?
                (innerDim_ - t * tileLen_) : tileLen_;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], len);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> maxLocal = scalarBuf_.Get<float>();
            AscendC::ReduceMax(maxLocal, xLocal, len);
            const float tileMax = maxLocal.GetValue(0);
            if (tileMax > rowMax) {
                rowMax = tileMax;
            }

            inQueueX_.FreeTensor(xLocal);
        }

        // ---- Pass 2: compute sum of exp(x - rowMax) ----
        float rowSum = 0.0f;
        for (uint32_t t = 0; t < numTiles; t++) {
            const uint32_t offset = rowBase + t * tileLen_;
            const uint32_t len = (t == numTiles - 1) ?
                (innerDim_ - t * tileLen_) : tileLen_;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], len);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> expLocal = tmpBuf1_.Get<float>();

            // exp(x - rowMax) = exp(x + (-rowMax))
            AscendC::Adds(expLocal, xLocal, -rowMax, len);
            AscendC::Exp(expLocal, expLocal, len);

            AscendC::LocalTensor<float> sumLocal = scalarBuf_.Get<float>();
            AscendC::ReduceSum(sumLocal, expLocal, len);
            rowSum += sumLocal.GetValue(0);

            inQueueX_.FreeTensor(xLocal);
        }

        // ---- Pass 3: normalize and write output ----
        const float invSum = 1.0f / (rowSum + 1e-12f);
        for (uint32_t t = 0; t < numTiles; t++) {
            const uint32_t offset = rowBase + t * tileLen_;
            const uint32_t len = (t == numTiles - 1) ?
                (innerDim_ - t * tileLen_) : tileLen_;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], len);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();

            // y = exp(x - rowMax) / sum = exp(x + (-rowMax)) * invSum
            AscendC::Adds(yLocal, xLocal, -rowMax, len);
            AscendC::Exp(yLocal, yLocal, len);
            AscendC::Muls(yLocal, yLocal, invSum, len);

            // Enqueue output then immediately dequeue and copy to GM
            outQueueY_.EnQue<float>(yLocal);
            yLocal = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yGm_[offset], yLocal, len);
            outQueueY_.FreeTensor(yLocal);

            inQueueX_.FreeTensor(xLocal);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> tmpBuf1_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> tmpBuf2_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> scalarBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t batchSize_ {0};
    uint32_t innerDim_ {0};
};

